INSERT INTO jobs (company_id, title, category, salary_min, salary_max, city, education, experience, headcount, highlights, description, requirement_text, status, posted_at)
SELECT c.id, jt.title, jt.category, jt.salary_min, jt.salary_max, jt.city, jt.education, jt.experience, jt.headcount, jt.highlights, jt.description, jt.requirement_text, 'OPEN', jt.posted_at
FROM companies c
JOIN (
  SELECT '北京' AS city, '前端开发工程师' AS title, '前端开发' AS category, 9000 AS salary_min, 16000 AS salary_max, '本科及以上' AS education, '1-3年' AS experience, 3 AS headcount, 'React,TypeScript,组件工程化' AS highlights, '负责招聘、企业展示和数据看板等 Web 前台模块，推动组件复用和交互体验优化。 团队位于北京，业务方向聚焦人工智能。' AS description, '熟悉 React、TypeScript、路由、表单和浏览器调试，理解接口联调和可访问性基础。' AS requirement_text, '2026-07-08 09:00:00' AS posted_at
  UNION ALL SELECT '北京' AS city, 'Java 后端开发工程师' AS title, '后端开发' AS category, 10300 AS salary_min, 18300 AS salary_max, '本科及以上' AS education, '1-3年' AS experience, 4 AS headcount, 'Java,Spring Boot,MySQL' AS highlights, '建设职位、企业、简历和投递流程 API，保障核心业务数据一致性与稳定性。 团队位于北京，业务方向聚焦人工智能。' AS description, '掌握 Java 基础、RESTful API、SQL 调优和常见 Web 安全策略。' AS requirement_text, '2026-07-08 08:00:00' AS posted_at
