INSERT INTO applications (job_id, applicant_id, status, message, interview_response)
SELECT j.id, u.id, 'SUBMITTED', '我对该岗位很感兴趣，希望有机会参与面试。', 'PENDING' FROM jobs j JOIN users u ON u.username = 'applicant' WHERE j.title = '前端开发工程师' AND j.city = '成都' LIMIT 1;

INSERT INTO applications (job_id, applicant_id, status, message, interview_response)
SELECT j.id, u.id, 'VIEWED', '我熟悉 Java Web 和 MySQL，希望参与后端服务开发。', 'PENDING' FROM jobs j JOIN users u ON u.username = 'applicant' WHERE j.title = 'Java 后端开发工程师' AND j.city = '成都' LIMIT 1;

